create table fournisseurs (id int primary key, reference_fournisseur varchar(256), nom_entreprise varchar(50) NOT NULL, nom_representant varchar(50), description_fournisseur TEXT, localisation varchar(50), quartier varchar(50), ville varchar(50), province_etat varchar(50), pays varchar(50), boite_postale varchar(50), siege_social varchar(50), email varchar(50), compte_fournisseur double NOT NULL, numero_telephone_1 varchar(28), numero_telephone_2 varchar(28), numero_contribuable varchar(256), image_fournisseur mediumblob, EMPLOYE boolean NOT NULL default FALSE, manager varchar(256), departement varchar(256), position_fonction varchar(256), groupes_dun_employe varchar(3000), groupes_dun_employe_ID varchar(5000), titres_employe varchar(256));
